function execute_with_replan(goal):
    plan = planner.run(goal)
    progress = []

    while plan.has_more(progress):
        step = plan.next(progress)
        try:
            obs = executor.run(step)
            if observer.dissents(step, obs):
                raise ReplanTrigger("observer dissent", obs)
            if surprising(obs, step.expected):
                raise ReplanTrigger("unexpected observation", obs)
            progress.append((step, obs))
        except (ToolError, ReplanTrigger) as exc:
            # preserve compatible partial progress
            keep = [(s, o) for (s, o) in progress
                    if plan.still_valid(s)]
            plan = planner.run(
                goal,
                progress=keep,
                failure=exc,
            )
            progress = keep

    return executor.summarise(goal, progress)

from datetime import timedelta
from temporalio import workflow
from temporalio.common import RetryPolicy
from temporalio.exceptions import ApplicationError


@workflow.defn
class ReplanOnFailure:
    @workflow.run
    async def run(self, goal: str) -> str:
        plan = await workflow.execute_activity(
            "plan", goal,
            start_to_close_timeout=timedelta(minutes=2),
        )
        progress: list[dict] = []

        for step in plan:
            try:
                obs = await workflow.execute_activity(
                    "execute_step", {"step": step, "progress": progress},
                    start_to_close_timeout=timedelta(minutes=5),
                    retry_policy=RetryPolicy(
                        initial_interval=timedelta(seconds=2),
                        maximum_attempts=3,
                        # non_retryable: planner-relevant signals
                        non_retryable_error_types=["ReplanTrigger"],
                    ),
                )
                progress.append({"step": step, "obs": obs})
            except ApplicationError as exc:
                if exc.type != "ReplanTrigger":
                    raise
                # replan with failure context; keep compatible progress
                plan = await workflow.execute_activity(
                    "plan",
                    {"goal": goal, "progress": progress, "failure": str(exc)},
                    start_to_close_timeout=timedelta(minutes=2),
                )
        return await workflow.execute_activity(
            "summarise", {"goal": goal, "progress": progress},
            start_to_close_timeout=timedelta(minutes=2),
        )

function rewoo(query):
    # Planner emits a DAG: each step references prior outputs as #t1 etc.
    # The planner does NOT see any tool observations.
    plan = planner.run(
        query,
        schema="""
        steps:
          - id: t1
            tool: ToolA
            args: {x: <literal>}
          - id: t2
            tool: ToolB
            args: {input: "#t1"}
        """,
    )

    # Worker executes in dependency order; substitutes #t_i references.
    results = {}
    for step in topological_order(plan.steps):
        args = substitute(step.args, results)   # #t1 -> results[t1]
        results[step.id] = run_tool(step.tool, args)

    # Solver sees the resolved trace and produces the final answer.
    return solver.run(query, plan=plan, results=results)

